module top_module(
    //# {{data|Data Signals}}
    input  D   ,
    output Q   ,

    //# {{clocks|Clocking}}
    input  CLK ,

    //# {{power|Power}}
    input  VPB ,
    input  VPWR,
    input  VGND,
    input  VNB
);reg obf_Q_reg;

    always @(posedge CLK)
        obf_Q_reg <= D;

    assign Q = obf_Q_reg;

endmodule
